import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useNavigate, Link } from "react-router-dom";
import { toast } from "react-toastify";
import {
  getB2bProfile,
  placeB2bOrder,
  payB2bOrder,
  clearB2bCart,
  addB2bAddress,
  resetB2bState,
} from "../../features/b2b/b2bSlice";
import B2bLayout from "./B2bLayout";
import {
  MapPin, Plus, ArrowLeft, CheckCircle2, CreditCard,
  FileText, AlertTriangle, Loader2, Wallet, User, Phone
} from "lucide-react";

const B2bCheckout = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const { cart, profile, isLoading, isSuccess, isError, message } = useSelector((s) => s.b2b);

  const [selectedAddress, setSelectedAddress] = useState(null);
  const [poNumber, setPoNumber] = useState("");
  const [notes, setNotes] = useState("");
  const [showAddressForm, setShowAddressForm] = useState(false);
  const [newAddr, setNewAddr] = useState({ label: "", recipientName: "", phone: "", line1: "", city: "", region: "", postalCode: "", isDefault: false });
  const [orderPlaced, setOrderPlaced] = useState(false);
  const [placedOrderId, setPlacedOrderId] = useState(null);

  useEffect(() => {
    dispatch(getB2bProfile());
  }, [dispatch]);

  useEffect(() => {
    if (profile?.addresses?.length > 0 && !selectedAddress) {
      const def = profile.addresses.find((a) => a.isDefault);
      setSelectedAddress(def?.id || profile.addresses[0].id);
    }
  }, [profile, selectedAddress]);

  // After order placed successfully, redirect based on payment method
  useEffect(() => {
    if (isSuccess && orderPlaced && !placedOrderId) {
      dispatch(clearB2bCart());
      dispatch(resetB2bState());
      navigate("/b2b/orders");
    }
  }, [isSuccess, orderPlaced, placedOrderId, dispatch, navigate]);

  const getUnitPrice = (item) => {
    const tiers = item.product.tierPricing || [];
    if (tiers.length > 0) {
      const sorted = [...tiers].sort((a, b) => b.minQty - a.minQty);
      const match = sorted.find((t) => item.quantity >= t.minQty);
      if (match) return parseFloat(match.unitPrice);
    }
    return parseFloat(item.product.wholesalePrice || 0);
  };

  const subtotal = cart.reduce((sum, i) => sum + getUnitPrice(i) * i.quantity, 0);

  const handleSubmitOrder = async () => {
    const orderData = {
      items: cart.map((i) => ({
        productId: i.product.id,
        quantity: i.quantity,
      })),
      shippingAddressId: selectedAddress,
      paymentMethod: "PREPAID",
      purchaseOrderNumber: poNumber || undefined,
      b2bNotes: notes || undefined,
    };
    setOrderPlaced(true);

    try {
      const result = await dispatch(placeB2bOrder(orderData)).unwrap();
      const orderId = result?.data?.id;

      // Always PREPAID — immediately initiate Chapa payment
      if (orderId) {
        setPlacedOrderId(orderId);
        try {
          const payResult = await dispatch(payB2bOrder(orderId)).unwrap();
          if (payResult?.payment_url) {
            dispatch(clearB2bCart());
            toast.success("Redirecting to Chapa for secure payment...");
            window.location.href = payResult.payment_url;
            return;
          }
        } catch (payErr) {
          toast.error("Order placed but payment start failed. You can pay from Order History.");
        }
      }

      dispatch(clearB2bCart());
      dispatch(resetB2bState());
      navigate("/b2b/orders");
    } catch (err) {
      // Error handled by Redux state
    }
  };

  const handleAddAddress = (e) => {
    e.preventDefault();
    dispatch(addB2bAddress(newAddr));
    setShowAddressForm(false);
    setNewAddr({ label: "", recipientName: "", phone: "", line1: "", city: "", region: "", postalCode: "", isDefault: false });
  };

  if (cart.length === 0 && !orderPlaced) {
    return (
      <B2bLayout>
        <div className="flex flex-col items-center justify-center py-28">
          <p className="text-slate-500 font-bold mb-4">Your cart is empty.</p>
          <Link to="/b2b" className="text-blue-600 font-bold underline">
            Go to catalog
          </Link>
        </div>
      </B2bLayout>
    );
  }

  return (
    <B2bLayout>
      <Link
        to="/b2b/cart"
        className="flex items-center gap-1.5 text-sm font-bold text-slate-400 hover:text-blue-600 transition-colors mb-6"
      >
        <ArrowLeft size={16} /> Back to Cart
      </Link>

      {profile && !profile.isVerified && (
        <div className="mb-6 p-4 sm:p-5 bg-gradient-to-r from-amber-500/10 to-orange-500/10 border border-amber-500/20 rounded-2xl sm:rounded-3xl flex flex-col sm:flex-row items-start gap-3 sm:gap-4 shadow-sm backdrop-blur-sm">
          <div className="w-10 h-10 bg-gradient-to-br from-amber-500 to-orange-500 text-white rounded-xl sm:rounded-2xl flex items-center justify-center shrink-0 shadow-md">
            <AlertTriangle size={20} />
          </div>
          <div>
            <h3 className="font-extrabold text-amber-950 leading-snug text-[14px] sm:text-[15px] flex items-center gap-1.5">
              Pending Verification
            </h3>
            <p className="text-amber-800 text-xs sm:text-sm font-semibold mt-1 leading-relaxed">
              Your B2B account is pending verification. You can browse the catalog and place orders via direct online payment (Chapa), but credit terms are disabled until verified.
            </p>
          </div>
        </div>
      )}

      <h1 className="text-2xl font-black text-slate-900 mb-8">Complete Your Order</h1>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* LEFT COLUMN */}
        <div className="lg:col-span-2 flex flex-col gap-6">
          {/* Shipping Address */}
          <div className="bg-white rounded-3xl border border-slate-100 p-6 shadow-sm">
            <h3 className="text-sm font-black text-slate-600 uppercase tracking-wider mb-5 flex items-center gap-2">
              <MapPin size={16} /> Shipping Address
            </h3>

            {profile?.addresses?.length > 0 ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-4">
                {profile.addresses.map((addr) => (
                  <button
                    key={addr.id}
                    onClick={() => setSelectedAddress(addr.id)}
                    className={`text-left p-4 rounded-2xl border-2 transition-all ${
                      selectedAddress === addr.id
                        ? "border-blue-500 bg-blue-50/50 shadow-md"
                        : "border-slate-100 hover:border-slate-200"
                    }`}
                  >
                    <div className="flex items-center gap-2 mb-2">
                      <span className="font-extrabold text-sm text-slate-800">{addr.label || "Address"}</span>
                      {addr.isDefault && (
                        <span className="text-[9px] font-black text-blue-600 bg-blue-100 px-2 py-0.5 rounded-full uppercase">
                          Default
                        </span>
                      )}
                      {selectedAddress === addr.id && <CheckCircle2 size={16} className="text-blue-500 ml-auto" />}
                    </div>
                    <p className="text-xs text-slate-500 font-medium leading-relaxed">
                      {addr.line1 || addr.street}, {addr.city}
                      {addr.region ? `, ${addr.region}` : ""}
                      {addr.postalCode ? ` ${addr.postalCode}` : ""}
                    </p>
                  </button>
                ))}
              </div>
            ) : (
              <p className="text-sm text-slate-500 mb-4">No addresses on file. Add one below.</p>
            )}

            {!showAddressForm ? (
              <button
                onClick={() => setShowAddressForm(true)}
                className="flex items-center gap-2 text-sm font-bold text-blue-600 hover:text-blue-800 transition-colors"
              >
                <Plus size={16} /> Add New Address
              </button>
            ) : (
              <form onSubmit={handleAddAddress} className="mt-4 bg-slate-50 rounded-2xl p-5 space-y-3">
                <div className="grid grid-cols-2 gap-3">
                  <input
                    placeholder="Label (e.g. Main Warehouse)"
                    value={newAddr.label}
                    onChange={(e) => setNewAddr({ ...newAddr, label: e.target.value })}
                    className="col-span-2 h-10 px-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20"
                    required
                  />
                  <div className="relative">
                    <User size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                    <input
                      placeholder="Recipient Name"
                      value={newAddr.recipientName}
                      onChange={(e) => setNewAddr({ ...newAddr, recipientName: e.target.value })}
                      className="w-full h-10 pl-9 pr-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20"
                      required
                    />
                  </div>
                  <div className="relative">
                    <Phone size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                    <input
                      placeholder="Phone (e.g. 0911234567)"
                      value={newAddr.phone}
                      onChange={(e) => setNewAddr({ ...newAddr, phone: e.target.value })}
                      className="w-full h-10 pl-9 pr-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20"
                      required
                    />
                  </div>
                  <input
                    placeholder="Street Address (Line 1)"
                    value={newAddr.line1}
                    onChange={(e) => setNewAddr({ ...newAddr, line1: e.target.value })}
                    className="col-span-2 h-10 px-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20"
                    required
                  />
                  <input
                    placeholder="City"
                    value={newAddr.city}
                    onChange={(e) => setNewAddr({ ...newAddr, city: e.target.value })}
                    className="h-10 px-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20"
                    required
                  />
                  <input
                    placeholder="Region / State"
                    value={newAddr.region}
                    onChange={(e) => setNewAddr({ ...newAddr, region: e.target.value })}
                    className="h-10 px-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20"
                  />
                  <input
                    placeholder="Postal Code"
                    value={newAddr.postalCode}
                    onChange={(e) => setNewAddr({ ...newAddr, postalCode: e.target.value })}
                    className="h-10 px-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20"
                  />
                  <label className="flex items-center gap-2 text-sm font-medium text-slate-600">
                    <input
                      type="checkbox"
                      checked={newAddr.isDefault}
                      onChange={(e) => setNewAddr({ ...newAddr, isDefault: e.target.checked })}
                      className="rounded"
                    />
                    Set as default
                  </label>
                </div>
                <div className="flex gap-3">
                  <button
                    type="submit"
                    className="bg-blue-600 text-white px-5 py-2.5 rounded-xl text-sm font-bold hover:bg-blue-700 transition-colors"
                  >
                    Save Address
                  </button>
                  <button
                    type="button"
                    onClick={() => setShowAddressForm(false)}
                    className="text-sm font-bold text-slate-500 hover:text-slate-700"
                  >
                    Cancel
                  </button>
                </div>
              </form>
            )}
          </div>

          {/* Payment Method */}
          <div className="bg-white rounded-3xl border border-slate-100 p-6 shadow-sm">
            <h3 className="text-sm font-black text-slate-600 uppercase tracking-wider mb-5 flex items-center gap-2">
              <CreditCard size={16} /> Payment Method
            </h3>
            <div className="flex items-center gap-4 p-4 rounded-2xl border-2 border-blue-500 bg-blue-50/50 shadow-md">
              <Wallet size={22} className="text-blue-600 shrink-0" />
              <div>
                <span className="font-extrabold text-sm text-slate-800 block">Pay Now (Chapa)</span>
                <span className="text-[11px] text-slate-500 font-medium">Secure online payment — you will be redirected to Chapa after placing your order</span>
              </div>
              <span className="ml-auto text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-md whitespace-nowrap">
                Redirects to Chapa
              </span>
            </div>
          </div>

          {/* PO & Notes */}
          <div className="bg-white rounded-3xl border border-slate-100 p-6 shadow-sm">
            <h3 className="text-sm font-black text-slate-600 uppercase tracking-wider mb-5 flex items-center gap-2">
              <FileText size={16} /> Additional Details
            </h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="text-xs font-bold text-slate-500 block mb-1.5">Purchase Order Number</label>
                <input
                  value={poNumber}
                  onChange={(e) => setPoNumber(e.target.value)}
                  placeholder="e.g. PO-2024-001234"
                  className="w-full h-11 px-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20"
                />
              </div>
              <div>
                <label className="text-xs font-bold text-slate-500 block mb-1.5">Delivery Notes</label>
                <input
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Special instructions..."
                  className="w-full h-11 px-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20"
                />
              </div>
            </div>
          </div>
        </div>

        {/* RIGHT — Summary */}
        <div className="lg:col-span-1">
          <div className="bg-white rounded-3xl border border-slate-100 p-6 shadow-sm sticky top-28">
            <h3 className="text-sm font-black text-slate-600 uppercase tracking-wider mb-5">
              Order Summary
            </h3>

            <div className="space-y-3 border-b border-slate-100 pb-5 mb-5 max-h-60 overflow-y-auto">
              {cart.map((item) => (
                <div key={item.product.id} className="flex justify-between text-sm">
                  <span className="text-slate-500 font-medium truncate mr-3 max-w-[160px]">
                    {item.product.title} ×{item.quantity}
                  </span>
                  <span className="font-bold text-slate-700 whitespace-nowrap">
                    {(getUnitPrice(item) * item.quantity).toLocaleString()} ETB
                  </span>
                </div>
              ))}
            </div>

            <div className="flex justify-between items-center mb-6">
              <span className="text-sm font-bold text-slate-500">Total</span>
              <span className="text-2xl font-black text-slate-950">
                {subtotal.toLocaleString()} <span className="text-xs font-bold text-slate-400">ETB</span>
              </span>
            </div>

            {isError && (
              <div className="flex items-center gap-2 text-rose-600 text-xs font-bold mb-4 bg-rose-50 rounded-xl p-3">
                <AlertTriangle size={14} />
                {typeof message === "string" ? message : "Failed to place order. Please try again."}
              </div>
            )}

            <button
              onClick={handleSubmitOrder}
              disabled={isLoading || !selectedAddress}
              className={`w-full h-14 rounded-2xl font-black uppercase tracking-wider text-sm flex items-center justify-center gap-3 transition-all ${
                isLoading
                  ? "bg-slate-200 text-slate-400"
                  : !selectedAddress
                  ? "bg-slate-200 text-slate-400 cursor-not-allowed"
                  : "bg-blue-600 text-white hover:bg-blue-700 shadow-lg shadow-blue-200"
              }`}
            >
              {isLoading ? (
                <><Loader2 size={18} className="animate-spin" /> Processing...</>
              ) : (
                "Place Procurement Order"
              )}
            </button>

            {!selectedAddress && (
              <p className="text-[11px] text-amber-600 font-bold mt-3 text-center">
                Please select or add a shipping address first.
              </p>
            )}
          </div>
        </div>
      </div>
    </B2bLayout>
  );
};

export default B2bCheckout;
